import{_ as r,a as t,b as a,m as i}from"./chunks/framework.DhA78p7M.js";const g=JSON.parse('{"title":"Supermic+more: PDM Bitstream ASICs for Audio Signal Processing","description":"Eight signal processing ASICs fabricated on the Skywater 130nm CMOS process via Tiny Tapeout 8, targeting beamforming and audio DSP for hearing aids.","frontmatter":{"title":"Supermic+more: PDM Bitstream ASICs for Audio Signal Processing","description":"Eight signal processing ASICs fabricated on the Skywater 130nm CMOS process via Tiny Tapeout 8, targeting beamforming and audio DSP for hearing aids.","longDescription":"PDM microphones have remarkable properties for beamforming. By manipulating the bitstream directly at 3072 kHz rather than converting to PCM first, delay-and-sum beamforming becomes simpler and more precise. This project implements these operations as ASICs using the Skywater 130nm CMOS process, with eight designs submitted for fabrication.","date":"2024-9-1"},"headers":[],"relativePath":"blogs/supermic/index.md","filePath":"blogs/supermic/index.md"}'),o={name:"blogs/supermic/index.md"};function n(s,e,l,m,c,h){return t(),a("div",null,[...e[0]||(e[0]=[i("",10)])])}const d=r(o,[["render",n]]);export{g as __pageData,d as default};
